import{_ as n,c as t,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Schnellstart: Installation, Konfiguration, Gateway-Start und erste Nachricht mit DM-Pairing-Schutz | Clawdbot Tutorial","description":"Dieses Kapitel führt dich durch die erste Verwendung von Clawdbot – von Installation, Konfiguration, Start des Gateway, Senden der ersten Nachricht bis zum Verständnis des DM-Pairing-Schutzmechanismus.","frontmatter":{"title":"Schnellstart: Installation, Konfiguration, Gateway-Start und erste Nachricht mit DM-Pairing-Schutz | Clawdbot Tutorial","sidebarTitle":"Start von Null","subtitle":"Schnellstart: Von der Installation zur ersten Nachricht","description":"Dieses Kapitel führt dich durch die erste Verwendung von Clawdbot – von Installation, Konfiguration, Start des Gateway, Senden der ersten Nachricht bis zum Verständnis des DM-Pairing-Schutzmechanismus.","tags":["Einstieg","Schnellstart"],"prerequisite":[],"order":10},"headers":[],"relativePath":"de/moltbot/moltbot/start/index.md","filePath":"de/moltbot/moltbot/start/index.md"}'),s={name:"de/moltbot/moltbot/start/index.md"};function r(l,e,o,u,h,d){return i(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="schnellstart-von-der-installation-zur-ersten-nachricht" tabindex="-1">Schnellstart: Von der Installation zur ersten Nachricht <a class="header-anchor" href="#schnellstart-von-der-installation-zur-ersten-nachricht" aria-label="Permalink to &quot;Schnellstart: Von der Installation zur ersten Nachricht&quot;">​</a></h1><p>Willkommen bei Clawdbot! Dieses Kapitel führt dich durch den vollständigen Prozess, Clawdbot von Null zu nutzen. Egal, ob du KI-Assistenten schnell ausprobieren oder Konfigurationsoptionen genauer verstehen möchtest – hier findest du die passenden Tutorials.</p><hr><h2 id="kapitelubersicht" tabindex="-1">Kapitelübersicht <a class="header-anchor" href="#kapitelubersicht" aria-label="Permalink to &quot;Kapitelübersicht&quot;">​</a></h2><p>Dieses Kapitel enthält 5 Tutorials, die den vollständigen Einstieg in Clawdbot abdecken: Von der Installation der Software, Konfiguration von KI-Modellen und Kommunikationskanälen, über den Start des Gateway-Dienstes, das Senden der ersten Nachricht bis zum Verständnis des Standardschutzmechanismus. Nach Abschluss dieses Kapitels hast du einen funktionsfähigen persönlichen KI-Assistenten.</p><hr><h2 id="empfohlener-lernpfad" tabindex="-1">Empfohlener Lernpfad <a class="header-anchor" href="#empfohlener-lernpfad" aria-label="Permalink to &quot;Empfohlener Lernpfad&quot;">​</a></h2><p>Wir empfehlen, diese Tutorials in folgender Reihenfolge zu durchlaufen:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[getting-started&lt;br&gt;Schnellstart] --&gt; B[onboarding-wizard&lt;br&gt;Assistent-gestützte Konfiguration]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[gateway-startup&lt;br&gt;Gateway starten]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[first-message&lt;br&gt;Erste Nachricht senden]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[pairing-approval&lt;br&gt;DM-Pairing &amp; Zugriffskontrolle]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#3b82f6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#10b981,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#f59e0b,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#8b5cf6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#ef4444,color:#fff</span></span></code></pre></div><p><strong>Erläuterung zur Lernreihenfolge</strong>:</p><ol><li><strong>Schnellstart</strong> (obligatorisch): Basisinstallation und -konfiguration abschließen – Grundlage für alle weiteren Lerninhalte</li><li><strong>Assistent-gestützte Konfiguration</strong> (empfohlen): Tiefere Einblicke in die Optionen des Assistenten, geeignet für Nutzer mit Bedarf an detaillierter Konfiguration</li><li><strong>Gateway starten</strong> (obligatorisch): Verstehen, wie der Gateway-Dienst gestartet und verwaltet wird</li><li><strong>Erste Nachricht senden</strong> (obligatorisch): Konfiguration verifizieren und KI-Assistenten nutzen</li><li><strong>DM-Pairing &amp; Zugriffskontrolle</strong> (empfohlen): Standardschutzmechanismen verstehen, um deinen KI-Assistenten zu schützen</li></ol><div class="tip custom-block"><p class="custom-block-title">Schneller Einstieg</p><p>Wenn du nur eine schnelle Testerfahrung möchtest, kannst du nur die Tutorials „Schnellstart&quot; und „Gateway starten&quot; durchgehen und direkt eine Nachricht senden. Die anderen Tutorials kannst du bei Bedarf später nachholen.</p></div><hr><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Bevor du dieses Kapitel bearbeitest, stelle bitte sicher, dass folgende Voraussetzungen erfüllt sind:</p><ul><li><strong>Node.js</strong>: ≥ 22.12.0 (mit <code>node -v</code> prüfen)</li><li><strong>Betriebssystem</strong>: macOS / Linux / Windows (WSL2)</li><li><strong>Paketmanager</strong>: npm / pnpm / bun</li><li><strong>KI-Modell-Konto</strong> (empfohlen): <ul><li>Anthropic Claude-Konto (Pro/Max-Abonnement), unterstützt OAuth-Fluss</li><li>oder API-Key eines anderen Anbieters wie OpenAI / DeepSeek / OpenRouter vorbereiten</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Hinweis für Windows-Nutzer</p><p>Auf Windows wird dringend empfohlen, <strong>WSL2</strong> zu verwenden, da:</p><ul><li>Viele Kanäle auf lokale Binärdateien angewiesen sind</li><li>Hintergrunddienste (launchd/systemd) unter Windows nicht verfügbar sind</li></ul></div><hr><h2 id="unterseiten-navigation" tabindex="-1">Unterseiten-Navigation <a class="header-anchor" href="#unterseiten-navigation" aria-label="Permalink to &quot;Unterseiten-Navigation&quot;">​</a></h2><h3 id="_1-schnellstart-⭐-kern-tutorial" tabindex="-1"><a href="./getting-started/">1. Schnellstart</a> ⭐ Kern-Tutorial <a class="header-anchor" href="#_1-schnellstart-⭐-kern-tutorial" aria-label="Permalink to &quot;[1. Schnellstart](./getting-started/) ⭐ Kern-Tutorial&quot;">​</a></h3><p><strong>Was kannst du nach dem Lernen</strong>:</p><ul><li>✅ Clawdbot auf deinem Gerät installieren</li><li>✅ KI-Modell-Authentifizierung konfigurieren (Anthropic / OpenAI / andere Anbieter)</li><li>✅ Gateway-Dienst starten</li><li>✅ Erste Nachricht über WebChat oder konfigurierte Kanäle senden</li></ul><p><strong>Zielgruppe</strong>: Alle Nutzer, Pflicht-Tutorial</p><p><strong>Geschätzte Zeit</strong>: 15-20 Minuten</p><p><strong>Hauptinhalte</strong>:</p><ul><li>Clawdbot mit npm/pnpm/bun installieren</li><li>Onboarding-Assistenten ausführen, um Basis-Konfiguration abzuschließen</li><li>Gateway starten und Status überprüfen</li><li>Testnachricht über CLI oder Kanäle senden</li></ul><p><strong>Voraussetzungen</strong>: Keine</p><hr><h3 id="_2-assistent-gestutzte-konfiguration" tabindex="-1"><a href="./onboarding-wizard/">2. Assistent-gestützte Konfiguration</a> <a class="header-anchor" href="#_2-assistent-gestutzte-konfiguration" aria-label="Permalink to &quot;[2. Assistent-gestützte Konfiguration](./onboarding-wizard/)&quot;">​</a></h3><p><strong>Was kannst du nach dem Lernen</strong>:</p><ul><li>✅ Vollständige Konfiguration mit interaktivem Assistenten durchführen</li><li>✅ Unterschied zwischen QuickStart- und Manual-Modus verstehen</li><li>✅ Gateway-Netzwerk, Authentifizierung und Tailscale konfigurieren</li><li>✅ KI-Modell-Anbieter einrichten (setup-token und API-Key)</li><li>✅ Kommunikationskanäle aktivieren (WhatsApp, Telegram usw.)</li><li>✅ Skill-Pakete installieren und verwalten</li></ul><p><strong>Zielgruppe</strong>: Nutzer mit Bedarf an detaillierter Konfiguration, Verständnis erweiterter Optionen</p><p><strong>Geschätzte Zeit</strong>: 20-30 Minuten</p><p><strong>Hauptinhalte</strong>:</p><ul><li>QuickStart vs. Manual-Modus: Auswahl</li><li>Gateway-Netzwerk-Konfiguration (Ports, Bindung, Authentifizierung)</li><li>KI-Modell-Authentifizierungsmethoden (setup-token empfohlen)</li><li>Konfigurationsprozess für Kommunikationskanäle</li><li>Einführung in das Skill-System</li></ul><p><strong>Voraussetzungen</strong>: <a href="./getting-started/">Schnellstart</a></p><hr><h3 id="_3-gateway-starten-⭐-kern-tutorial" tabindex="-1"><a href="./gateway-startup/">3. Gateway starten</a> ⭐ Kern-Tutorial <a class="header-anchor" href="#_3-gateway-starten-⭐-kern-tutorial" aria-label="Permalink to &quot;[3. Gateway starten](./gateway-startup/) ⭐ Kern-Tutorial&quot;">​</a></h3><p><strong>Was kannst du nach dem Lernen</strong>:</p><ul><li>✅ Gateway-Vordergrundprozess über Kommandozeile starten</li><li>✅ Gateway als Hintergrunddienst konfigurieren (macOS LaunchAgent / Linux systemd / Windows Scheduled Task)</li><li>✅ Verschiedene Bindungsmodi (loopback / LAN / Tailnet) und Authentifizierungsmethoden verstehen</li><li>✅ Zwischen Entwicklungs- und Produktionsmodus wechseln</li><li>✅ <code>--force</code> verwenden, um belegte Ports zu erzwingen</li></ul><p><strong>Zielgruppe</strong>: Alle Nutzer, Pflicht-Tutorial</p><p><strong>Geschätzte Zeit</strong>: 15-20 Minuten</p><p><strong>Hauptinhalte</strong>:</p><ul><li>Vordergrundmodus vs. Dienstmodus</li><li>Auswahl des Bindungsmodus (loopback / LAN / Tailnet / Auto)</li><li>Konfiguration der Authentifizierungsmethode (Token / Passwort / Tailscale Identity)</li><li>Entwicklungsmodus (<code>--dev</code>) und Produktionsmodus</li><li>Dienstverwaltungsbefehle (install / start / stop / restart)</li><li>Behandlung von Port-Konflikten (<code>--force</code>)</li></ul><p><strong>Voraussetzungen</strong>: <a href="./onboarding-wizard/">Assistent-gestützte Konfiguration</a></p><hr><h3 id="_4-erste-nachricht-senden-⭐-kern-tutorial" tabindex="-1"><a href="./first-message/">4. Erste Nachricht senden</a> ⭐ Kern-Tutorial <a class="header-anchor" href="#_4-erste-nachricht-senden-⭐-kern-tutorial" aria-label="Permalink to &quot;[4. Erste Nachricht senden](./first-message/) ⭐ Kern-Tutorial&quot;">​</a></h3><p><strong>Was kannst du nach dem Lernen</strong>:</p><ul><li>✅ Nachricht über WebChat-Oberfläche senden</li><li>✅ Über konfigurierte Kanäle (WhatsApp / Telegram / Slack usw.) mit KI-Assistenten kommunizieren</li><li>✅ Nachrichten-Routing und Antwortabläufe verstehen</li><li>✅ Grundlegende Aufgaben mit KI-Assistenten ausführen (Abfragen, Zusammenfassungen, Code-Generierung usw.)</li></ul><p><strong>Zielgruppe</strong>: Alle Nutzer, Pflicht-Tutorial</p><p><strong>Geschätzte Zeit</strong>: 10-15 Minuten</p><p><strong>Hauptinhalte</strong>:</p><ul><li>Nutzung der WebChat-Oberfläche</li><li>Nachrichtenversand über verschiedene Kanäle</li><li>Nachrichtenformat und Antwortmechanismus</li><li>Beispiele für häufige Aufgaben (Informationen abfragen, Code generieren, Text zusammenfassen)</li><li>Debugging und Fehlerbehebung</li></ul><p><strong>Voraussetzungen</strong>: <a href="./gateway-startup/">Gateway starten</a></p><hr><h3 id="_5-dm-pairing-zugriffskontrolle" tabindex="-1"><a href="./pairing-approval/">5. DM-Pairing &amp; Zugriffskontrolle</a> <a class="header-anchor" href="#_5-dm-pairing-zugriffskontrolle" aria-label="Permalink to &quot;[5. DM-Pairing &amp; Zugriffskontrolle](./pairing-approval/)&quot;">​</a></h3><p><strong>Was kannst du nach dem Lernen</strong>:</p><ul><li>✅ Standardmäßigen DM-Pairing-Schutzmechanismus verstehen</li><li>✅ Pairing-Anfragen unbekannter Absender genehmigen oder ablehnen</li><li>✅ Whitelist und Blacklist konfigurieren</li><li>✅ Zugriffskontrollrichtlinien einstellen</li><li>✅ Pairing-Modi und Sicherheits-Best-Practices verstehen</li></ul><p><strong>Zielgruppe</strong>: Sicherheitsbewusste Nutzer, empfohlene Lektüre</p><p><strong>Geschätzte Zeit</strong>: 10-15 Minuten</p><p><strong>Hauptinhalte</strong>:</p><ul><li>Funktionsweise des DM-Pairing-Mechanismus</li><li>Pairing-Ablauf und Nutzererlebnis</li><li>Whitelist- und Blacklist-Konfiguration</li><li>Einstellung der Zugriffskontrollrichtlinien</li><li>Sicherheits-Best-Practices</li></ul><p><strong>Voraussetzungen</strong>: <a href="./first-message/">Erste Nachricht senden</a></p><hr><h2 id="haufig-gestellte-fragen" tabindex="-1">Häufig gestellte Fragen <a class="header-anchor" href="#haufig-gestellte-fragen" aria-label="Permalink to &quot;Häufig gestellte Fragen&quot;">​</a></h2><h3 id="f-sollte-ich-alle-tutorials-durchlaufen" tabindex="-1">F: Sollte ich alle Tutorials durchlaufen? <a class="header-anchor" href="#f-sollte-ich-alle-tutorials-durchlaufen" aria-label="Permalink to &quot;F: Sollte ich alle Tutorials durchlaufen?&quot;">​</a></h3><p><strong>A</strong>: Nicht unbedingt. Wenn du schnell einsteigen möchtest, reichen die beiden Kern-Tutorials „Schnellstart&quot; und „Gateway starten&quot;, dann kannst du direkt mit Clawdbot loslegen. Die anderen Tutorials kannst du bei Bedarf später nachholen.</p><h3 id="f-hat-es-auswirkungen-wenn-ich-bestimmte-tutorials-uberspringe" tabindex="-1">F: Hat es Auswirkungen, wenn ich bestimmte Tutorials überspringe? <a class="header-anchor" href="#f-hat-es-auswirkungen-wenn-ich-bestimmte-tutorials-uberspringe" aria-label="Permalink to &quot;F: Hat es Auswirkungen, wenn ich bestimmte Tutorials überspringe?&quot;">​</a></h3><p><strong>A</strong>: Nein. Jedes Tutorial ist eigenständig, aber „Schnellstart&quot; ist die Grundlage und enthält Installation und Basis-Konfiguration – daher empfohlen als Erstes. Die anderen Tutorials kannst du je nach Bedarf auswählen.</p><h3 id="f-ich-bin-bereits-mit-ki-assistenten-vertraut-kann-ich-die-basis-tutorials-uberspringen" tabindex="-1">F: Ich bin bereits mit KI-Assistenten vertraut, kann ich die Basis-Tutorials überspringen? <a class="header-anchor" href="#f-ich-bin-bereits-mit-ki-assistenten-vertraut-kann-ich-die-basis-tutorials-uberspringen" aria-label="Permalink to &quot;F: Ich bin bereits mit KI-Assistenten vertraut, kann ich die Basis-Tutorials überspringen?&quot;">​</a></h3><p><strong>A</strong>: Ja. Wenn du bereits mit ähnlichen KI-Assistenten-Tools vertraut bist, kannst du „Schnellstart&quot; überspringen und direkt „Assistent-gestützte Konfiguration&quot; und „Gateway starten&quot; durcharbeiten, um die spezifische Konfiguration und Startweise von Clawdbot kennenzulernen.</p><h3 id="f-was-kann-ich-nach-abschluss-dieses-kapitels-tun" tabindex="-1">F: Was kann ich nach Abschluss dieses Kapitels tun? <a class="header-anchor" href="#f-was-kann-ich-nach-abschluss-dieses-kapitels-tun" aria-label="Permalink to &quot;F: Was kann ich nach Abschluss dieses Kapitels tun?&quot;">​</a></h3><p><strong>A</strong>: Nach Abschluss hast du ein funktionsfähiges Clawdbot-System und kannst:</p><ul><li>Über WebChat oder mehrere Kanäle mit dem KI-Assistenten kommunizieren</li><li>Der KI grundlegende Aufgaben zuweisen (Informationen abfragen, Code generieren, Text zusammenfassen usw.)</li><li>Sicherheit durch DM-Pairing-Mechanismus gewährleisten</li><li>Fortgeschrittene Funktionen erlernen (Multi-Channel-Konfiguration, Tool-System, Skill-Plattform usw.)</li></ul><hr><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels kannst du folgende Themen vertiefen:</p><ul><li><strong><a href="./../../platforms/channels-overview/">Übersicht Multi-Channel-System</a></strong>: Alle von Clawdbot unterstützten Kommunikationskanäle und deren Merkmale kennenlernen</li><li><strong><a href="./../../platforms/whatsapp/">WhatsApp-Kanal</a></strong>: Vertiefte Einblicke in Konfiguration und Nutzung des WhatsApp-Kanals</li><li><strong><a href="./../../platforms/telegram/">Telegram-Kanal</a></strong>: Vertiefte Einblicke in Konfiguration und Nutzung des Telegram-Kanals</li><li><strong><a href="./../../platforms/webchat/">WebChat-Oberfläche</a></strong>: Funktionen der integrierten WebChat-Oberfläche kennenlernen</li></ul><div class="tip custom-block"><p class="custom-block-title">Hinweis</p><p>Wähle je nach Nutzungsbedarf die entsprechenden Kanäle für vertieftes Lernen aus. Wenn du hauptsächlich einen bestimmten Kanal nutzt (z.B. WhatsApp oder Telegram), kannst du dessen spezielles Tutorial priorisieren.</p></div>`,79)])])}const p=n(s,[["render",r]]);export{c as __pageData,p as default};
